pub fn http_executor_fee(input_len: usize, output_len: usize) -> U256 {
    let input_component =
        U256::from(HTTP_EXECUTOR_FEE_PER_INPUT_BYTE_WEI) * U256::from(input_len as u64);
    let output_component =
        U256::from(HTTP_EXECUTOR_FEE_PER_OUTPUT_BYTE_WEI) * U256::from(output_len as u64);
    U256::from(HTTP_EXECUTOR_BASE_FEE_WEI) + input_component + output_component
}

#[test]
fn test_http_executor_fee_zero_output() {
    let fee = http_executor_fee(256, 0);
    let expected_base = U256::from(HTTP_EXECUTOR_BASE_FEE_WEI);
    let expected_input = U256::from(HTTP_EXECUTOR_FEE_PER_INPUT_BYTE_WEI) * U256::from(256);
    assert_eq!(fee, expected_base + expected_input);
}

pub fn http_executor_fee(input_len: usize, output_len: usize) -> U256 {
    let input_component =
        U256::from(HTTP_EXECUTOR_FEE_PER_INPUT_BYTE_WEI) * U256::from(input_len as u64);
    let output_component =
        U256::from(HTTP_EXECUTOR_FEE_PER_OUTPUT_BYTE_WEI) * U256::from(output_len as u64);
    U256::from(HTTP_EXECUTOR_BASE_FEE_WEI) + input_component + output_component
}

#[test]
fn test_http_executor_fee_with_output() {
    let fee = http_executor_fee(256, 1024);
    assert!(fee > U256::from(HTTP_EXECUTOR_BASE_FEE_WEI));
}
